// ============================================================
// Node: Extract Order Data
// WF1 - Extraction et structuration données commande Shopify
// ============================================================


const order = $input.first().json;

// SÉCURITÉ : validation commande
if (!order || !order.id) {
  throw new Error('[WF1] Commande Shopify invalide ou données manquantes');
}

// --- PRODUITS : "1 Aspirateur ; 2 SOLID TAPE" ---
const lineItems = order.line_items || [];
const produitsStr = lineItems
  .map(item => `${item.quantity} ${item.title}`)
  .join(' ; ') || 'Produit inconnu';

// --- TÉLÉPHONE : priorité shipping > billing > customer ---
let phone =
  order.shipping_address?.phone ||
  order.billing_address?.phone ||
  order.phone ||
  order.customer?.phone ||
  '';
phone = phone.replace(/[\s\-\(\)]/g, '');
if (phone && !phone.startsWith('+')) {
  phone = phone.startsWith('689') ? '+' + phone : '+689' + phone;
}

// --- EMAIL CLIENT ---
const emailClient =
  order.contact_email ||
  order.email ||
  order.customer?.email ||
  '';

// --- LIEU DE LIVRAISON ---
const sh = order.shipping_address || {};
const lieuLivraison = [sh.address1, sh.city].filter(Boolean).join(', ') || 'Non spécifié';

// --- NOM CLIENT ---
const clientName = `${order.customer?.first_name || ''} ${order.customer?.last_name || ''}`.trim() || 'Client';

// --- DATE (format Tahiti) ---
const tahitiTime = new Date().toLocaleString("en-US", {timeZone: "Pacific/Tahiti"});
const now = new Date(tahitiTime);
const dateStr = (String(now.getDate()).padStart(2, '0') + '/' + String(now.getMonth() + 1).padStart(2, '0') + '/' + now.getFullYear());

// --- PRIX TOTAL ---
const totalPrice = parseFloat(order.total_price || 0);
const prixTotal = `${Math.round(totalPrice)} F`;

// --- DÉTECTION FRET (correspondance EXACTE) ---
const shippingLines = order.shipping_lines || [];
const shippingTitle = shippingLines[0]?.title || '';
const isFret = (shippingTitle === 'Fret pour les îles');


// --- DÉTECTION DÉPÔT-VENTE ---
const shippingTitleLower = shippingTitle.toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '');
const isDepotVente = shippingTitleLower.includes('recup')
                  || shippingTitleLower.includes('depot');
return [{
  json: {
    idShopify:      order.id.toString(),
    refCommande:    `#${order.order_number}`,
    date:           dateStr,
    aClient:        clientName,
    telephone:      phone,
    emailClient:    emailClient,
    lieuLivraison:  lieuLivraison,
    produits:       produitsStr,
    prixTotal:      prixTotal,
    livraison:      'Livraison en attente',
    isFret:         isFret,
    isDepotVente:   isDepotVente,
    shippingTitle:  shippingTitle,
    orderId:        order.id
  }
}];

// ============================================================
// Node: Determine Target Tab
// WF1 - Quel onglet Google Sheets pour cette commande ?
// ============================================================

const data = $input.first().json;

// Luxon weekday: 1=Lun, 2=Mar, 3=Mer, 4=Jeu, 5=Ven, 6=Sam, 7=Dim
const tahitiTime = new Date().toLocaleString("en-US", {timeZone: "Pacific/Tahiti"});
const now = new Date(tahitiTime);
const weekday = (now.getDay() === 0 ? 7 : now.getDay());

const dayTabMap = {
  1: 'Lundi',
  2: 'Mardi',
  3: 'Mercredi',
  4: 'Jeudi',
  5: 'Vendredi',
  6: 'Samedi'
};

// --- 1. DÉTECTION ZONES ÉLOIGNÉES ---
const remoteZones = [
  'mataiea', 'paea', 'papara', 'mahina', 'tiarei', 'faaone', 
  'taravao', 'vairao', 'teahupoo', 'tautira', 'papenoo', 
  'hitiaa', 'papeari'
];

let isRemoteZone = false;
const addressToSearch = (data.lieuLivraison || '').toLowerCase();
// Enlever les accents pour sécuriser la recherche
const normalizedAddress = addressToSearch.normalize("NFD").replace(/[\u0300-\u036f]/g, "");

for (const zone of remoteZones) {
  if (normalizedAddress.includes(zone)) {
    isRemoteZone = true;
    break;
  }
}

// --- 2. ROUTAGE (Ordre de priorité : FRET > Zone Éloignée > J+1) ---
let targetTab;

if (data.isFret) {
  // FRET → onglet FRET (indépendant de la ville et du jour)
  targetTab = 'FRET';
} else if (data.isDepotVente) {
  // DÉPÔT-VENTE → onglet dépôt-vente
  targetTab = 'DEPOT_VENTE';
} else if (isRemoteZone) {
  // Zone Éloignée → TOUJOURS le Samedi
  targetTab = 'Samedi';
} else {
  // Commande standard → ROUTAGE 
  // Vendredi (5), Samedi (6) et Dimanche (7) vont tous les trois au Lundi
  if (weekday === 5 || weekday === 6 || weekday === 7) {
    targetTab = 'Lundi';
  } else {
    // Lundi->Mardi (2), Mardi->Mercredi (3), Mercredi->Jeudi (4), Jeudi->Vendredi (5)
    targetTab = dayTabMap[weekday + 1] || 'Lundi';
  }
}

return [{
  json: {
    ...data,
    targetTab: targetTab,
    isDepotVente:  data.isDepotVente,
    isRemoteZone:  isRemoteZone,
    orderWeekdayOrigin: weekday
  }
}];

